// On toggle
function setWireframeMode(enabled) {
  document.documentElement.dataset.fidelity = enabled ? 'wireframe' : '';
  localStorage.setItem('wireframe-mode', enabled ? 'true' : 'false');
}

// On page load
const saved = localStorage.getItem('wireframe-mode');
if (saved === 'true') {
  document.documentElement.dataset.fidelity = 'wireframe';
}

